import subprocess, re

# Get dynamic symbols sorted by address
result = subprocess.run(['readelf', '-sW', 'libmonosgen-2.0.so'], capture_output=True, text=True)
symbols = []
for line in result.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 8:
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            stype = parts[3]
            name = parts[7] if len(parts) > 7 else ''
            if addr > 0 and stype == 'FUNC' and name:
                symbols.append((addr, size, name))
        except (ValueError, IndexError):
            pass

symbols.sort()

def find_symbol(pc):
    best = None
    for addr, size, name in symbols:
        if addr <= pc:
            best = (addr, size, name)
        else:
            break
    if best:
        offset = pc - best[0]
        if best[1] == 0 or offset < best[1]:
            return f'{best[2]}+0x{offset:x}'
    return '???'

# Addresses from tombstone for libmonosgen-2.0.so
addrs = [0x222098, 0x222234, 0x19bac0, 0x19bc14]
for a in addrs:
    print(f'  0x{a:08x} -> {find_symbol(a)}')
"

